@app.route('/mfa/setup', methods=['POST'])
@login_required
def setup_mfa():
    """Initialize MFA setup - generates a TOTP secret and QR code."""
    user_id = session['user_id']
    user = users_db[user_id]

    if user['mfa_enabled'] and user['mfa_verified']:
        return jsonify({'error': 'MFA is already enabled. Disable it first to reconfigure.'}), 400

    # Generate new TOTP secret
    secret = pyotp.random_base32()
    user['mfa_secret'] = secret
    user['mfa_verified'] = False

    # Generate provisioning URI for QR code
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")

    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode('utf-8')

    return jsonify({
        'message': 'MFA setup initiated. Scan the QR code with your authenticator app and verify with a code.',
        'secret': secret,
        'qr_code': f'data:image/png;base64,{qr_base64}',
        'provisioning_uri': provisioning_uri
    }), 200


@app.route('/mfa/verify-setup', methods=['POST'])
@login_required
def verify_mfa_setup():
    """Verify MFA setup by confirming a TOTP code from the authenticator app."""
    user_id = session['user_id']
    user = users_db[user_id]

    if not user['mfa_secret']:
        return jsonify({'error': 'MFA setup has not been initiated. Call /mfa/setup first.'}), 400

    if user['mfa_enabled'] and user['mfa_verified']:
        return jsonify({'error': 'MFA is already enabled and verified.'}), 400

    data = request.get_json()
    if not data or not data.get('mfa_code'):
        return jsonify({'error': 'MFA code is required to verify setup'}), 400

    mfa_code = data['mfa_code']
    totp = pyotp.TOTP(user['mfa_secret'])

    if not totp.verify(mfa_code, valid_window=1):
        return jsonify({'error': 'Invalid MFA code. Please try again.'}), 400

