@app.route('/mfa/disable', methods=['POST'])
@login_required
def disable_mfa():
    """Disable MFA for the current user (requires password confirmation)."""
    user_id = session['user_id']
    user = users_db[user_id]

    if not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not currently enabled'}), 400

    data = request.get_json()
    if not data or not data.get('password'):
        return jsonify({'error': 'Password confirmation is required to disable MFA'}), 400

    if not check_password_hash(user['password_hash'], data['password']):
        return jsonify({'error': 'Invalid password'}), 401

    # Optionally require current MFA code for extra security
    if data.get('mfa_code'):
        totp = pyotp.TOTP(user['mfa_secret'])
        if not totp.verify(data['mfa_code'], valid_window=1):
            return jsonify({'error': 'Invalid MFA code'}), 401

    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_verified'] = False
    user['backup_codes'] = []

    return jsonify({'message': 'MFA has been successfully disabled'}), 200


